(window.webpackJsonp=window.webpackJsonp||[]).push([[382],{1009:function(n,t){n.exports="\x3c!-- \ntitle: CSS\nsort: \n--\x3e \n\n## 加特技\n\n```scss\n// 渐变\nbackground: linear-gradient(to bottom right, #7ffb, #4bfb);\n\n// 阴影\n/* x偏移量 | y偏移量 | 阴影模糊半径 | 阴影扩散半径 | 阴影颜色 */\nbox-shadow: 7px 7px 10px 7px rgba(0, 0, 0, 0.2);\n\n// 文字阴影\n/* x偏移量 | y偏移量 | 阴影模糊半径  | 阴影颜色 */\ntext-shadow: 5px 5px 5px 5px #fffb;\n\n// 背景图\nbackground: url(bgimg.gif) no-repeat 5px 5px;\n\nmargin: \n/* 二值语法  纵向 横向 */\n/* 三值语法 上 横向 下 */\n/* 四值语法 上 右 下 左 */\n\ntext-align: center;\t\t/* 文字居中 */\n\n// canvas全屏\n* {\n  margin: 0;\n  padding: 0;\n}\nhtml,\nbody {\n  height: 100%;\n  width: 100%;\n}\ncanvas.width = window.innerWidth;\ncanvas.height = window.innerHeight;\n```\n\n### div居中\n\n```css\n/* 方式1 */\n.center {\n  margin: auto;\n\n  position: absolute;\n  top: 0;\n  left: 0;\n  right: 0;\n  bottom: 0;\n  \n  text-align: center; /* 让div内部文字居中 */\n\n  background-color: #fff;\n  border-radius: 20px;\n  width: 300px;\n  height: 350px;\n}\n\n/* 方式2 */\n.center {\n  position: absolute;\n  left: 50%;\n  top: 50%;\n  transform: translate(-50%, -50%);\n  \n  text-align: center;\n\n  background-color: #fff;\n  border-radius: 20px;\n  width: 300px;\n  height: 350px;\n}\n```\n\n"}}]);